mapper.select:
SELECT d.dormitory_id, d.name AS dormitory_name, r.room_id, r.room_name, CASE WHEN COALESCE(active.cnt, 0) >= r.capacity THEN 'OCCUPIED' ELSE 'VACANT' END AS status, active.resident_name, active.residence_history_id, active.expected_move_out_date, CASE WHEN COALESCE(active.cnt, 0) < r.capacity THEN TRUE ELSE FALSE END AS assignable FROM room r JOIN dormitory d ON d.dormitory_id = r.dormitory_id AND d.deleted_at IS NULL LEFT JOIN ( SELECT rh.room_id, rh.residence_history_id, e.name AS resident_name, rh.move_out_date AS expected_move_out_date, COUNT(1) AS cnt FROM residence_history rh JOIN employee e ON e.employee_id = rh.employee_id AND e.deleted_at IS NULL WHERE rh.deleted_at IS NULL AND rh.move_in_date <= COALESCE(#{asOfDate}, CURRENT_DATE) AND (rh.move_out_date IS NULL OR rh.move_out_date >= COALESCE(#{asOfDate}, CURRENT_DATE)) GROUP BY rh.room_id, rh.residence_history_id, e.name, rh.move_out_date ) active ON active.room_id = r.room_id WHERE r.deleted_at IS NULL
AND d.gender_type = #{gender}
ORDER BY d.name, r.room_name LIMIT #{limit} OFFSET #{offset}

SELECT r.room_id, r.room_name, r.dormitory_id FROM room r JOIN dormitory d ON d.dormitory_id = r.dormitory_id AND d.deleted_at IS NULL JOIN employee e ON e.employee_id = #{employeeId} AND e.deleted_at IS NULL LEFT JOIN ( SELECT rh.room_id, COUNT(1) AS cnt FROM residence_history rh WHERE rh.deleted_at IS NULL AND rh.move_in_date <= COALESCE(#{asOfDate}, CURRENT_DATE) AND (rh.move_out_date IS NULL OR rh.move_out_date >= COALESCE(#{asOfDate}, CURRENT_DATE)) GROUP BY rh.room_id ) active ON active.room_id = r.room_id WHERE r.deleted_at IS NULL AND d.gender_type = CASE e.gender WHEN 'MALE' THEN 'MALE' WHEN 'FEMALE' THEN 'FEMALE' END
AND r.dormitory_id = #{dormitoryId}
AND COALESCE(active.cnt, 0) < r.capacity ORDER BY r.dormitory_id, r.room_name LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1) FROM room r JOIN dormitory d ON d.dormitory_id = r.dormitory_id AND d.deleted_at IS NULL JOIN employee e ON e.employee_id = #{employeeId} AND e.deleted_at IS NULL LEFT JOIN ( SELECT rh.room_id, COUNT(1) AS cnt FROM residence_history rh WHERE rh.deleted_at IS NULL AND rh.move_in_date <= COALESCE(#{asOfDate}, CURRENT_DATE) AND (rh.move_out_date IS NULL OR rh.move_out_date >= COALESCE(#{asOfDate}, CURRENT_DATE)) GROUP BY rh.room_id ) active ON active.room_id = r.room_id WHERE r.deleted_at IS NULL AND d.gender_type = CASE e.gender WHEN 'MALE' THEN 'MALE' WHEN 'FEMALE' THEN 'FEMALE' END
AND r.dormitory_id = #{dormitoryId}
AND COALESCE(active.cnt, 0) < r.capacity
